"use client"

import { useFinancial } from "@/hooks/useFinancial"
import { Navigation } from "@/components/navigation"
import { AuthGuard } from "@/components/auth-guard"
import { Card } from "@/components/ui/card"
import { Label } from "@/components/ui/label"
import { Switch } from "@/components/ui/switch"
import { Moon, Sun, Monitor } from "lucide-react"

export default function SettingsPage() {
  const { data, updateSettings } = useFinancial()

  return (
    <AuthGuard>
      
      <div className="flex h-screen bg-background text-foreground">
        <Navigation />
        <main className="flex-1 overflow-auto">
          <div className="p-8 max-w-2xl mx-auto">
            <h2 className="text-3xl font-bold mb-8">Configurações</h2>

            <div className="space-y-6">
              {/* Seção de Aparência */}
              <Card className="p-6">
                <h3 className="text-lg font-semibold mb-4 flex items-center gap-2">
                  <Monitor className="w-5 h-5" /> Aparência
                </h3>
                <div className="flex items-center justify-between">
                  <div className="space-y-0.5">
                    <Label>Modo Escuro</Label>
                    <p className="text-sm text-muted-foreground">
                      Alternar entre os temas claro e escuro.
                    </p>
                  </div>
                  <div className="flex items-center gap-2">
                    <Sun className="w-4 h-4 text-muted-foreground" />
                    <Switch
                      checked={data.settings.theme === "dark"}
                      onCheckedChange={(checked) =>
                        updateSettings({ theme: checked ? "dark" : "light" })
                      }
                    />
                    <Moon className="w-4 h-4 text-muted-foreground" />
                  </div>
                </div>
              </Card>

              {/* Nota sobre o sistema */}
              <p className="text-xs text-center text-muted-foreground pt-4">
                Versão 1.0.0 • FinPlan Sistema de Gestão Financeira
              </p>
            </div>
          </div>
        </main>
      </div>
    </AuthGuard>
  )
}